};

scwin.ds_SeaAFRMarks_onloadcompleted = function(e) {
    let rowcnt = ds_SeaAFRMarks.getRowCount();
    if (rowcnt == 0) {
    } else {
        let markVal = ds_SeaAFRMarks.getCellData(ds_SeaAFRMarks.getRowPosition(), "mark");
        let Split = markVal.split("\n");
        if (Split[0] != undefined) txt_mark1.setValue(Split[0]);
        if (Split[1] != undefined) txt_mark2.setValue(Split[1]);
        if (Split[2] != undefined) txt_mark3.setValue(Split[2]);
        if (Split[3] != undefined) txt_mark4.setValue(Split[3]);
    }
};

scwin.ds_SeaAFR_onrowpositionchange = async function(info) {
    let row = ds_SeaAFR.getRowPosition();
    if (ds_SeaAFR.getCellData(row, "flag") == "1") {
        dma_Search2.set("hblno", ds_SeaAFR.getCellData(row, "hblno"));
        dma_Search2.set("mblno", ds_SeaAFR.getCellData(row, "mblno"));
        dma_Search2.set("mhno", ds_SeaAFR.getCellData(row, "mhno"));
        await $c.sbm.execute(sbm_retrieveMarks);
    }
    scwin.f_ByteCheck();
};

scwin.sbm_retrieveCont2_submitdone = async function(e) {
    let rowcnt = ds_SeaAFRCont2.getRowCount();
    if (rowcnt == 0) {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_002);
        return;
    } else {
        let cnt3 = 0;
        for (let i = 0; i < ds_SeaAFRCont2.getRowCount(); i++) {
            for (let j = 0; j < ds_SeaAFRCont.getRowCount(); j++) {
                if (ds_SeaAFRCont.getCellData(j, "hblno") == ds_SeaAFRCont2.getCellData(i, "hblno") &&
                    ds_SeaAFRCont.getCellData(j, "mhno") == ds_SeaAFRCont2.getCellData(i, "mhno") &&
                    ds_SeaAFRCont.getCellData(j, "mblno") == ds_SeaAFRCont2.getCellData(i, "mblno") &&
                    ds_SeaAFRCont.getCellData(j, "cntrNo") == ds_SeaAFRCont2.getCellData(i, "cntrNo")) {
                    cnt3++;
                    ds_SeaAFRCont.setCellData(j, "kcomcd", ds_SeaAFRCont2.getCellData(i, "kcomcd"));
                    ds_SeaAFRCont.setCellData(j, "mrn", ds_SeaAFRCont2.getCellData(i, "mrn"));
                    ds_SeaAFRCont.setCellData(j, "mblno", ds_SeaAFRCont2.getCellData(i, "mblno"));
                    ds_SeaAFRCont.setCellData(j, "hblno", ds_SeaAFRCont2.getCellData(i, "hblno"));
                    ds_SeaAFRCont.setCellData(j, "mhno", ds_SeaAFRCont2.getCellData(i, "mhno"));
                    ds_SeaAFRCont.setCellData(j, "cntrNo", ds_SeaAFRCont2.getCellData(i, "cntrNo"));
                    ds_SeaAFRCont.setCellData(j, "cntrSeq", ds_SeaAFRCont2.getCellData(i, "cntrSeq"));
                    ds_SeaAFRCont.setCellData(j, "cntrType", ds_SeaAFRCont2.getCellData(i, "cntrType"));
                    ds_SeaAFRCont.setCellData(j, "seal1", ds_SeaAFRCont2.getCellData(i, "seal1"));
                    ds_SeaAFRCont.setCellData(j, "seal2", ds_SeaAFRCont2.getCellData(i, "seal2"));
                    ds_SeaAFRCont.setCellData(j, "seal3", ds_SeaAFRCont2.getCellData(i, "seal3"));
                    ds_SeaAFRCont.setCellData(j, "cntrOwnerCd", ds_SeaAFRCont2.getCellData(i, "cntrOwnerCd"));
                    ds_SeaAFRCont.setCellData(j, "regId", ds_SeaAFRCont2.getCellData(i, "regId"));
                    ds_SeaAFRCont.setCellData(j, "modId", ds_SeaAFRCont2.getCellData(i, "modId"));
                }
            }
            if (cnt3 == 0) {
                ds_SeaAFRCont.insertRow();
                let newRowPos = ds_SeaAFRCont.getRowPosition();
                ds_SeaAFRCont.setCellData(newRowPos, "kcomcd", ds_SeaAFRCont2.getCellData(i, "kcomcd"));
                ds_SeaAFRCont.setCellData(newRowPos, "mrn", ds_SeaAFRCont2.getCellData(i, "mrn"));
                ds_SeaAFRCont.setCellData(newRowPos, "mblno", ds_SeaAFRCont2.getCellData(i, "mblno"));
                ds_SeaAFRCont.setCellData(newRowPos, "hblno", ds_SeaAFRCont2.getCellData(i, "hblno"));
                ds_SeaAFRCont.setCellData(newRowPos, "mhno", ds_SeaAFRCont2.getCellData(i, "mhno"));
                ds_SeaAFRCont.setCellData(newRowPos, "cntrNo", ds_SeaAFRCont2.getCellData(i, "cntrNo"));
                ds_SeaAFRCont.setCellData(newRowPos, "cntrSeq", ds_SeaAFRCont2.getCellData(i, "cntrSeq"));
                ds_SeaAFRCont.setCellData(newRowPos, "cntrType", ds_SeaAFRCont2.getCellData(i, "cntrType"));
                ds_SeaAFRCont.setCellData(newRowPos, "seal1", ds_SeaAFRCont2.getCellData(i, "seal1"));
                ds_SeaAFRCont.setCellData(newRowPos, "seal2", ds_SeaAFRCont2.getCellData(i, "seal2"));
                ds_SeaAFRCont.setCellData(newRowPos, "seal3", ds_SeaAFRCont2.getCellData(i, "seal3"));
                ds_SeaAFRCont.setCellData(newRowPos, "cntrOwnerCd", ds_SeaAFRCont2.getCellData(i, "cntrOwnerCd"));
                ds_SeaAFRCont.setCellData(newRowPos, "regId", scwin.ID);
                ds_SeaAFRCont.setCellData(newRowPos, "modId", scwin.ID);
            }
            cnt3 = 0;
        }
        let cnt4 = 0;
        for (let i = 0; i < ds_SeaAFRCont.getRowCount(); i++) {
            for (let j = 0; j < ds_SeaAFRCont2.getRowCount(); j++) {
                if (ds_SeaAFRCont.getCellData(i, "hblno") == ds_SeaAFRCont2.getCellData(j, "hblno") &&
                    ds_SeaAFRCont.getCellData(i, "mhno") == ds_SeaAFRCont2.getCellData(j, "mhno") &&
                    ds_SeaAFRCont.getCellData(i, "mblno") == ds_SeaAFRCont2.getCellData(j, "mblno") &&
                    ds_SeaAFRCont.getCellData(i, "cntrNo") == ds_SeaAFRCont2.getCellData(j, "cntrNo")) {
                    cnt4++;
                }
            }
            if (cnt4 == 0) {
                ds_SeaAFRCont.removeRow(i);
            }
            cnt4 = 0;
        }
    }
};

