        if (ds_SeaAFR.getCellData(rowPos, "shipperAddr4") != ds_SeaAFR2.getCellData(0, "shipperAddr4"))
            ds_SeaAFR.setCellData(rowPos, "shipperAddr4", ds_SeaAFR2.getCellData(0, "shipperAddr4"));
        if (ds_SeaAFR.getCellData(rowPos, "consigneeNm") != ds_SeaAFR2.getCellData(0, "consigneeNm"))
            ds_SeaAFR.setCellData(rowPos, "consigneeNm", ds_SeaAFR2.getCellData(0, "consigneeNm"));
        if (ds_SeaAFR.getCellData(rowPos, "consigneeAddr1") != ds_SeaAFR2.getCellData(0, "consigneeAddr1"))
            ds_SeaAFR.setCellData(rowPos, "consigneeAddr1", ds_SeaAFR2.getCellData(0, "consigneeAddr1"));
        if (ds_SeaAFR.getCellData(rowPos, "consigneeAddr2") != ds_SeaAFR2.getCellData(0, "consigneeAddr2"))
            ds_SeaAFR.setCellData(rowPos, "consigneeAddr2", ds_SeaAFR2.getCellData(0, "consigneeAddr2"));
        if (ds_SeaAFR.getCellData(rowPos, "consigneeAddr3") != ds_SeaAFR2.getCellData(0, "consigneeAddr3"))
            ds_SeaAFR.setCellData(rowPos, "consigneeAddr3", ds_SeaAFR2.getCellData(0, "consigneeAddr3"));
        if (ds_SeaAFR.getCellData(rowPos, "consigneeAddr4") != ds_SeaAFR2.getCellData(0, "consigneeAddr4"))
            ds_SeaAFR.setCellData(rowPos, "consigneeAddr4", ds_SeaAFR2.getCellData(0, "consigneeAddr4"));
        if (ds_SeaAFR.getCellData(rowPos, "pkg") != ds_SeaAFR2.getCellData(0, "pkg"))
            ds_SeaAFR.setCellData(rowPos, "pkg", ds_SeaAFR2.getCellData(0, "pkg"));
        if (ds_SeaAFR.getCellData(rowPos, "unitCd") != ds_SeaAFR2.getCellData(0, "unitCd"))
            ds_SeaAFR.setCellData(rowPos, "unitCd", ds_SeaAFR2.getCellData(0, "unitCd"));
